inline void fill_dense(Matrix& M, int rows, int cols,
                       const std::vector<double>& vals) {
  if (static_cast<int>(vals.size()) != rows * cols) {
    throw std::runtime_error("fill_dense size mismatch");
  }
  M.resize(rows, cols);
  for (int r = 0; r < rows; ++r) {
    for (int c = 0; c < cols; ++c) {
      M(r, c) =
          vals[static_cast<std::size_t>(r) * static_cast<std::size_t>(cols) +
               static_cast<std::size_t>(c)];
    }
  }
}

